const GOD_BY_SLUG: Record<string, EgyptianGuide> = Object.fromEntries(EGYPTIAN_GODS.map((g) => [g.slug, g]))

export const EGYPTIAN_GOD_SLUGS = EGYPTIAN_GODS.map((g) => g.slug)

export function isEgyptianGodSlug(s: string): boolean {
  return s in GOD_BY_SLUG
}

